import streamlit as stfrom streamlit_gsheets import GSheetsConnectionimport pandas as pdfrom datetime import datetime, timedeltaimport urllib.parseimport plotly.express as pximport warnings# Gereksiz uyarıları gizlewarnings.filterwarnings("ignore")# --- 1. SAYFA AYARLARI ---st.set_page_config(    page_title="Bostanlı Çözüm VIP",     layout="wide",     page_icon="🏫",    initial_sidebar_state="collapsed" )# Tasarım ve Üst Menü Stili (CSS)st.markdown("""    <style>    #MainMenu {visibility: hidden;}    footer {visibility: hidden;}    header {visibility: hidden;}    .stDeployButton {display:none;}    .stTabs [data-baseweb="tab-list"] {        gap: 15px;        background-color: #f0f2f6;        padding: 10px;        border-radius: 10px;    }    .stTabs [data-baseweb="tab"] {        height: 50px;        background-color: #ffffff;        border-radius: 5px;        font-weight: bold;    }    </style>    """, unsafe_allow_html=True)# --- 2. ÇİFTLİ ŞİFRE SİSTEMİ ---def check_password():    if "user_role" not in st.session_state:        st.title("🔐 Kurumsal Yönetim Paneli")        pwd = st.text_input("Giriş Şifresi", type="password")        if st.button("Sisteme Giriş Yap"):            if pwd == "cozum35":                st.session_state["user_role"] = "admin"                st.rerun()            elif pwd == "personel35":                st.session_state["user_role"] = "staff"                st.rerun()            else:                st.error("❌ Hatalı şifre.")        return False    return Trueif check_password():    conn = st.connection("gsheets", type=GSheetsConnection)    role = st.session_state["user_role"]    def wa_link(tel, mesaj):        tel_str = str(tel).replace(" ", "").replace("-", "").replace("(", "").replace(")", "")        if tel_str.startswith("0"): tel_str = "90" + tel_str[1:]        elif not tel_str.startswith("90"): tel_str = "90" + tel_str        return f"https://wa.me/{tel_str}?text={urllib.parse.quote(mesaj)}"    # Üst Başlık ve Güvenli Çıkış    c_title, c_exit = st.columns([4, 1])    with c_title:        st.title(f"🏫 Bostanlı Çözüm VIP ({'Kurucu' if role == 'admin' else 'Personel'} Paneli)")    with c_exit:        if st.button("🚪 Güvenli Çıkış"):            del st.session_state["user_role"]            st.rerun()    # --- 3. RAPORLAMA FONKSİYONU (Ortak Kullanım) ---    def load_full_report(target_date_str):        try:            dv = conn.read(worksheet="gorusmeler", ttl=0)            dk = conn.read(worksheet="kasa", ttl=0)            do = conn.read(worksheet="olaylar", ttl=0)                        dv_b = dv[dv['Tarih'].astype(str).str.contains(target_date_str, na=False)]            dk_b = dk[dk['Tarih'].astype(str).str.contains(target_date_str, na=False)]            do_b = do[do['Tarih'].astype(str).str.contains(target_date_str, na=False)]                        dk_b['Miktar'] = pd.to_numeric(dk_b['Miktar'], errors='coerce').fillna(0)            gelir_df = dk_b[dk_b['Tip'] == 'Gelir (Tahsilat)']            gider_df = dk_b[dk_b['Tip'] == 'Gider (Ödeme)']                        t_gelir = gelir_df['Miktar'].sum()            t_gider = gider_df['Miktar'].sum()            # WhatsApp Metni (Tam Detaylı)            msg = f"*🏫 BOSTANLI ÇÖZÜM VIP GÜNLÜK RAPOR ({datetime.strptime(target_date_str, '%Y-%m-%d').strftime('%d.%m.%Y')})*\n\n"            msg += f"*📊 ÖZET*\n📞 Görüşme: {len(dv_b)}\n💰 Gelir: {t_gelir:,.0f} TL\n💸 Gider: {t_gider:,.0f} TL\n📈 Net: {t_gelir - t_gider:,.0f} TL\n\n"                        if not do_b.empty:                msg += "*🚨 ÖNEMLİ OLAYLAR*\n"                for _, r in do_b.iterrows(): msg += f"- [{r['Olay Tipi']}] {r['Detay']}\n"                msg += "\n"            if not gelir_df.empty:                msg += "*💰 TAHSİLAT DETAYLARI*\n"                for _, r in gelir_df.iterrows(): msg += f"- {r['Kategori']}: {r['Miktar']:,.0f} TL ({r['Detay']})\n"                msg += "\n"            if not dv_b.empty:                msg += "*📞 YAPILAN GÖRÜŞMELER*\n"                for _, r in dv_b.iterrows():                     msg += f"- Vel: {r['Veli Ad Soyad']} / Öğr: {r['Öğrenci Ad Soyad']} ({r['Konu']}) - Yapan: {r.get('Görüşmeyi Yapan','-')}\n"            return {"dv_b": dv_b, "gelir_df": gelir_df, "gider_df": gider_df, "do_b": do_b, "t_gelir": t_gelir, "t_gider": t_gider, "msg": msg}        except: return None    # --- 4. YETKİLENDİRİLMİŞ SEKMELER ---    if role == "admin":        tabs = st.tabs(["📊 Kurucu Raporu", "📈 Gelişmiş Analiz"])    else:        tabs = st.tabs(["📞 Veli Görüşmeleri", "💰 Kasa İşlemleri", "🚨 Günlük Olaylar", "📝 Raporu İlet"])    # --- 🔵 KURUCU PANELİ İÇERİĞİ ---    if role == "admin":        with tabs[0]: # KURUCU RAPORU            st.header("📊 Günlük Faaliyet Raporu")            t_sec_raw = st.date_input("Rapor Tarihi", datetime.now(), format="DD/MM/YYYY")            res = load_full_report(t_sec_raw.strftime("%Y-%m-%d"))                        if res:                m1, m2, m3, m4 = st.columns(4)                m1.metric("Görüşme", len(res["dv_b"]))                m2.metric("Gelir", f"{res['t_gelir']:,.0f} TL")                m3.metric("Gider", f"{res['t_gider']:,.0f} TL")                m4.metric("Net", f"{res['t_gelir'] - res['t_gider']:,.0f} TL", delta=float(res['t_gelir'] - res['t_gider']))                st.divider()                c1, c2 = st.columns(2)                with c1:                    st.subheader("💰 Gelir / Tahsilat Listesi")                    st.dataframe(res["gelir_df"][['Kategori', 'Miktar', 'Detay']], use_container_width=True)                with c2:                    st.subheader("📞 Bugünün Görüşmeleri")                    st.dataframe(res["dv_b"][['Veli Ad Soyad', 'Öğrenci Ad Soyad', 'Konu', 'Durum', 'Görüşmeyi Yapan']], use_container_width=True)                if not res["do_b"].empty:                    st.warning("🚨 Kayıtlı Önemli Olaylar")                    st.table(res["do_b"][['Olay Tipi', 'Detay']])                st.markdown(f'### [(📲 Detaylı Raporu WhatsApp ile Gönder)]({wa_link("905492551912", res["msg"])})')        with tabs[1]: # GELİŞMİŞ ANALİZ            st.header("📈 Finansal & Operasyonel Analiz")            try:                dk_all = conn.read(worksheet="kasa", ttl=0)                dv_all = conn.read(worksheet="gorusmeler", ttl=0)                dk_all['Miktar'] = pd.to_numeric(dk_all['Miktar'], errors='coerce').fillna(0)                dk_all['Tarih'] = pd.to_datetime(dk_all['Tarih'], errors='coerce')                dv_all['Tarih'] = pd.to_datetime(dv_all['Tarih'], errors='coerce')                                c_a, c_b = st.columns(2)                b_t = c_a.date_input("Analiz Başlangıç", datetime.now() - timedelta(days=90), format="DD/MM/YYYY")                e_t = c_b.date_input("Analiz Bitiş", datetime.now(), format="DD/MM/YYYY")                                df_f_k = dk_all[(dk_all['Tarih'].dt.date >= b_t) & (dk_all['Tarih'].dt.date <= e_t)]                df_f_v = dv_all[(dv_all['Tarih'].dt.date >= b_t) & (dv_all['Tarih'].dt.date <= e_t)]                                col1, col2 = st.columns(2)                with col1:                    st.plotly_chart(px.pie(df_f_k[df_f_k['Tip'] == 'Gelir (Tahsilat)'], values='Miktar', names='Kategori', title="Gelir Dağılımı", hole=0.4), use_container_width=True)                    st.plotly_chart(px.bar(df_f_v['Durum'].value_counts().reset_index(), x='Durum', y='count', title="Görüşme Sonuçları", color='Durum'), use_container_width=True)                with col2:                    st.plotly_chart(px.pie(df_f_k[df_f_k['Tip'] == 'Gider (Ödeme)'], values='Miktar', names='Kategori', title="Gider Dağılımı", hole=0.4), use_container_width=True)                    if 'Görüşmeyi Yapan' in df_f_v.columns:                        st.plotly_chart(px.bar(df_f_v['Görüşmeyi Yapan'].value_counts().reset_index(), x='Görüşmeyi Yapan', y='count', title="Personel Performansı (Görüşme Sayısı)"), use_container_width=True)            except: st.error("Veri yetersiz veya hata oluştu.")    # --- 🟢 PERSONEL PANELİ İÇERİĞİ ---    else:        with tabs[0]: # VELİ GÖRÜŞMELERİ            st.header("📞 Veli Görüşme Kayıt & Düzenleme")            try: df_v = conn.read(worksheet="gorusmeler", ttl=0)            except: df_v = pd.DataFrame(columns=["Tarih", "Veli Ad Soyad", "Öğrenci Ad Soyad", "Telefon", "Konu", "Durum", "Notlar", "Görüşmeyi Yapan"])                        with st.expander("➕ Yeni Görüşme Ekle", expanded=False):                with st.form("v_form_staff", clear_on_submit=True):                    v_t = st.date_input("Tarih", datetime.now())                    c1, c2 = st.columns(2)                    v_a = c1.text_input("Veli Ad Soyad *")                    o_a = c1.text_input("Öğrenci Ad Soyad *")                    v_tel = c2.text_input("Telefon *")                    v_ko = c2.selectbox("Konu *", ["Seçiniz...", "Yeni Kayıt", "YKS Hazırlık", "LGS Hazırlık", "Ara Sınıf Hazırlık", "Online Kamp", "Yüz Yüze Kamp", "Kayıt Silme", "Diğer"])                    v_yapan = st.selectbox("Görüşmeyi Yapan Personel *", ["Seçiniz...", "Tufan Bey", "Eğitim Koordinatörü", "Rehberlik", "Ofis Yönetimi", "Diğer"])                    v_du = st.selectbox("Durum *", ["Beklemede", "Olumlu", "Olumsuz", "Kayıt Tamamlandı", "İptal"])                    v_no = st.text_area("Görüşme Notları")                    if st.form_submit_button("Kaydı Tamamla"):                        if v_a and o_a and v_ko != "Seçiniz..." and v_yapan != "Seçiniz...":                            new = pd.DataFrame([{"Tarih": v_t.strftime("%Y-%m-%d"), "Veli Ad Soyad": v_a, "Öğrenci Ad Soyad": o_a, "Telefon": v_tel, "Konu": v_ko, "Durum": v_du, "Notlar": v_no, "Görüşmeyi Yapan": v_yapan}])                            conn.update(worksheet="gorusmeler", data=pd.concat([df_v, new], ignore_index=True))                            st.success("Kayıt Başarılı!")                            v_msg = f"Sayın {v_a}, bugün {o_a} için yaptığımız görüşme için teşekkür ederiz."                            st.markdown(f'### [👉 Velimize Mesaj Gönder (WhatsApp)]({wa_link(v_tel, v_msg)})')                        else: st.error("Eksik alan var!")            st.subheader("🔍 Kayıtları Düzenle")            v_edited = st.data_editor(df_v, num_rows="dynamic", key="v_edit_p")            if st.button("Görüşmeleri Güncelle"):                 conn.update(worksheet="gorusmeler", data=v_edited)                st.success("Görüşmeler güncellendi!")        with tabs[1]: # KASA İŞLEMLERİ            st.header("💰 Kasa İşlemleri & Düzenleme")            try: df_k = conn.read(worksheet="kasa", ttl=0)            except: df_k = pd.DataFrame(columns=["Tarih", "Tip", "Kategori", "Miktar", "Detay"])                        with st.expander("➕ Yeni Kasa İşlemi"):                k_t = st.date_input("Kasa Tarihi", datetime.now())                k_ti = st.radio("Tür", ["Gelir (Tahsilat)", "Gider (Ödeme)"], horizontal=True)                k_ka = st.selectbox("Kategori", ["Aidat Ödemesi", "Yayın Paketi", "Özel Ders", "Kira", "Maaş", "Fatura", "Diğer"])                k_tu = st.number_input("Tutar (TL)", min_value=0.0)                k_de = st.text_input("Açıklama")                if st.button("Kasaya İşle"):                    if k_tu > 0:                        new_k = pd.DataFrame([{"Tarih": k_t.strftime("%Y-%m-%d"), "Tip": k_ti, "Kategori": k_ka, "Miktar": k_tu, "Detay": k_de}])                        conn.update(worksheet="kasa", data=pd.concat([df_k, new_k], ignore_index=True))                        st.success("Kasa Güncellendi!")                        st.data_editor(df_k, num_rows="dynamic", key="k_edit_p")            if st.button("Kasayı Güncelle"):                 conn.update(worksheet="kasa", data=st.session_state.k_edit_p)        with tabs[2]: # GÜNLÜK OLAYLAR            st.header("🚨 Olay Kaydı")            try: df_o = conn.read(worksheet="olaylar", ttl=0)            except: df_o = pd.DataFrame(columns=["Tarih", "Olay Tipi", "Detay"])            with st.form("o_f_p"):                o_t = st.date_input("Olay Tarihi", datetime.now())                o_ti = st.selectbox("Tip", ["Acil", "Denetim", "Ziyaretçi", "Şikayet"])                o_de = st.text_area("Açıklama")                if st.form_submit_button("Olayı Kaydet"):                    new_o = pd.DataFrame([{"Tarih": o_t.strftime("%Y-%m-%d"), "Olay Tipi": o_ti, "Detay": o_de}])                    conn.update(worksheet="olaylar", data=pd.concat([df_o, new_o], ignore_index=True))                    st.success("Olay kaydedildi.")        with tabs[3]: # PERSONEL RAPOR GÖNDER            st.header("📝 Kurucuya Günlük Raporu İlet")            p_res = load_full_report(datetime.now().strftime("%Y-%m-%d"))            if p_res:                st.metric("Bugünkü Toplam Tahsilat", f"{p_res['t_gelir']:,.0f} TL")                st.markdown(f'### [(📲 DETAYLI RAPORU TUFAN BEY\'E GÖNDER)]({wa_link("905492551912", p_res["msg"])})')